import React from 'react';
import { useNavigate } from 'react-router-dom';
import { removeToken } from '../utils/auth.js';
import { Search } from 'lucide-react';

export default function Navbar() {
  const navigate = useNavigate();

  const handleLogout = () => {
    removeToken();
    navigate('/login');
  };

  return (
    <div className="flex justify-between items-center mb-8">

      {/* 🔍 SEARCH BAR */}
      <div className="flex items-center bg-white/5 border border-white/10 rounded-xl px-4 py-2 w-80 backdrop-blur-lg">
        <Search size={18} className="text-gray-400" />
        <input
          type="text"
          placeholder="Search transactions..."
          className="bg-transparent outline-none text-white ml-2 w-full placeholder-gray-500"
        />
      </div>

      {/* 👤 PROFILE SECTION */}
      <div className="flex items-center gap-4">

        <div className="text-right hidden sm:block">
          <p className="text-sm text-gray-400">Welcome back</p>
          <p className="text-white font-semibold">Sumit</p>
        </div>

        {/* Avatar */}
        <div className="w-10 h-10 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold shadow-lg">
          S
        </div>

        {/* Logout */}
        <button
          onClick={handleLogout}
          className="bg-red-500 px-4 py-2 rounded-xl text-white hover:bg-red-600 transition shadow-md"
        >
          Logout
        </button>

      </div>

    </div>
  );
}
